@dataclass(frozen=True)
class FigureConfig:
    step5_root: Path = DEFAULT_STEP5_ROOT
    step4_model_ready_csv: Path = DEFAULT_STEP4_MODEL_READY
    export_png: bool = True
    export_pdf: bool = True
