# -----------------------------------------------------------------------------
# Infer likely run directories from discovered checkpoints/logs/configs
# -----------------------------------------------------------------------------
def parent_dirs(paths: list[Path], max_depth_up: int = 2) -> list[Path]:
    out: list[Path] = []
    seen: set[Path] = set()
    for p in paths:
        cur = p.parent
        for _ in range(max_depth_up):
            if cur not in seen and cur.exists():
                seen.add(cur)
                out.append(cur)
            cur = cur.parent
    return out

