    add_panel_label_aligned_to_ylabel(fig, ax_b, "b", x_extra=-0.006, y_extra=0.001)
    add_panel_label_aligned_to_ylabel(fig, ax_c, "c", x_extra=-0.006, y_extra=0.001)

    save_figure(fig, FIG_SUPP_DIR / "SuppFig_2_6_1_redesign_v9")

