def main_notebook(cfg: Optional[Step8Config] = None) -> Dict[str, Any]:
    if cfg is None:
        cfg = Step8Config()

    seed_all(cfg.main_random_seed)
    project_root = Path(cfg.project_root).resolve()
    step7_root = project_root / cfg.step7_dir
