    print(f"Supplementary figures: {dirs['figures_supplementary']}")
    print(f"Artifacts: {dirs['artifacts']}")
    print(f"Reports: {dirs['reports']}")
    print(f"Logs: {dirs['logs']}")
    print("=" * 100)

    return results


