        pd.to_numeric(get_1d_column(final_panel_df, "entropy"), errors="coerce"),
        pd.to_numeric(get_1d_column(final_panel_df, "nearest_reference_similarity"), errors="coerce"),
        s=45,
        facecolor=PROJECT_COLORS["pepcvae_navy"],
        edgecolor="white",
