    ax_a.tick_params(axis="x", pad=8)
    ax_a.set_ylabel("NN similarity")
    ax_a.set_ylim(0, 0.16)
    ax_a.set_title("NN similarity support", loc="left", pad=8, x=0.08)

    # -------------------------------------------------------------------------
    # Panel b
    # -------------------------------------------------------------------------
    ax_b = fig.add_subplot(gs[0, 1])
